package tests;import base.BaseTest;import pages.AdminPage;import pages.LoginPage;import org.junit.jupiter.api.Assertions;import org.junit.jupiter.api.Test;public class HP08FiltrarPedidosEstadoMesTest extends BaseTest {    @Test    void administradorFiltraPedidosPorEstadoYMes() {        try {            System.out.println("Ejecutando HP-08: Administrador filtra pedidos por estado y mes");            LoginPage loginPage = new LoginPage(driver);            loginPage.abrirLogin();            loginPage.iniciarSesion("admin", "admin");            Thread.sleep(3000);            AdminPage adminPage = new AdminPage(driver);            Assertions.assertTrue(                    adminPage.panelAdministradorVisible(),                    "No se visualiza el Panel Administrador."            );            adminPage.seleccionarEstado("delivered");            adminPage.seleccionarMes("6");            adminPage.filtrar();            Thread.sleep(3000);            Assertions.assertTrue(                    adminPage.estadisticasVisibles(),                    "No se muestran las estadísticas después del filtro."            );            Assertions.assertTrue(                    adminPage.estadoEnTablaVisible("delivered"),                    "No se muestran pedidos con estado delivered."            );            System.out.println("HP-08 ejecutado correctamente.");        } catch (Exception e) {            Assertions.fail("Error en HP-08: " + e.getMessage());        }    }}